@ARTICLE{10.2174/0109298673438731251212115733,
	author = {Bao Y and Du Y and Wang D and Li J and Yao F and Wu Q},
	title = {Potential Role and Mechanisms of Epigallocatechin-3-Gallate in Colorectal Cancer.},
	journal = {Curr Med Chem},
	year = {2026},
	abstract = {Colorectal cancer (CRC), the second deadliest cancer worldwide, is characterized by high incidence and poor prognosis. Although current treatments can effectively relieve patient symptoms, numerous toxic side effects remain unresolved. Therefore, treating CRC remains a substantial challenge, and novel approaches are urgently needed. Epigallocatechin-3-gallate (EGCG), a natural polyphenol and the most abundant component of green tea, exerts preventive and anticancer effects. Herein, we review previous literature and summarize the effects of EGCG on the prevention and treatment of CRC. EGCG has been shown to inhibit cell proliferation, growth, and invasion, trigger apoptosis, and enhance sensitivity to chemotherapy and radiotherapy in patients with CRC. EGCG inhibits tumorigenesis through several mechanisms, mainly involving modulation of signaling pathways, suppression of inflammation, and regulation of gut microbiota in preclinical studies. However, the instability and low bioavailability of EGCG limit its clinical applications, and developing novel EGCG nanoparticles is an important future research direction. In conclusion, EGCG has proven valuable in suppressing CRC progression both in vitro and in vivo. Furthermore, the safety and efficacy of EGCG for treating CRC in clinical practice need to be further explored. The data were gathered by searching relevant information in multiple databases, such as PubMed, ScienceDirect, and Google Scholar.},
	doi = {10.2174/0109298673438731251212115733},
	pmid = {41863176}
}

@ARTICLE{10.1016/j.carbpol.2026.125138,
	author = {Chen X and Li N and Cheng H and Zhang Y and Pan R and Shen Q and Yan G},
	title = {Dynamic polysaccharide-based organic nanocomposite hydrogel precisely mediates oral targeted therapy for colorectal cancer.},
	journal = {Carbohydr Polym},
	year = {2026},
	abstract = {Overcoming the gastrointestinal barrier to enable precise oral drug delivery to the small intestine and colorectum is crucial for the treatment of colorectal cancer (CRC). Herein, this work highlights a dynamic polysaccharide-based organic nanocomposite hydrogel, which is successfully fabricated through incorporating lipophilic orthoester (OE)/carboxymethyl chitosan (CMCS)-based nano-prodrugs (NPs) into the gellan gum (GG) matrix. The GG can not only protect OE/NPs from gastric acid-induced degradation and ensure precise release in the small intestine and colon via pH-triggered progressive pore expansion, but also alter gut microbiota composition. OE can promote the efficient release of NPs from the hydrogel network through phase separation and subsequently restore their original particle size via its hydrolysis in the small intestine and colon. NPs can promote intestinal absorption and transport, and enhance targeted accumulation and selective synergistic cytotoxicity at CRC sites through deprotonation/protonation and dynamic size changes. Thus, the dynamic polysaccharide-based organic nanocomposite hydrogel precisely mediates oral targeted therapy for CRC, greatly advancing its application in clinics.},
	doi = {10.1016/j.carbpol.2026.125138},
	pmid = {41832032 [Indexed for MEDLINE]}
}

