@ARTICLE{10.1111/jgh.70245,
	author = {Farah H and Kadhim-Abosaoda M and Mohaisen-Mousa H and Jyothi R and Priyadarshini-Nayak P and Janney-J B and Singh G and Singh-Chauhan A and Kumar-Mishra M},
	title = {Exosome-Based Strategies in Hepatocellular Carcinoma: Mechanisms, Immunotherapy, and Clinical Challenges.},
	journal = {J Gastroenterol Hepatol},
	year = {2026},
	abstract = {Hepatocellular carcinoma (HCC) remains one of the most prevalent and lethal malignancies worldwide, characterized by late diagnosis, limited therapeutic options, and poor prognosis. Conventional systemic therapies such as sorafenib and its successors provide only modest survival benefits and are frequently complicated by toxicity and drug resistance. In recent years, immunotherapy has emerged as a promising avenue, yet its efficacy is often restricted by the profoundly immunosuppressive tumor microenvironment (TME). Within this landscape, exosomes-nanoscale extracellular vesicles secreted by tumor, stromal, and immune cells-have gained increasing attention for their central role in intercellular communication. They influence immune modulation, metabolic reprogramming, and therapeutic resistance, while also serving as potential biomarkers, nanocarriers, and vaccine platforms. Tumor-derived exosomes (TEXs) contribute to immune evasion by suppressing CD8+ T cells, polarizing macrophages toward protumoral phenotypes, and enhancing immune checkpoint resistance. Conversely, engineered exosomes demonstrate significant therapeutic potential by reprogramming TAMs, improving drug delivery, and acting as cancer vaccines. Despite these advances, challenges remain in exosome biogenesis, heterogeneity, large-scale production, and off-target effects, which hinder clinical translation. Furthermore, interactions between exosomes and gut microbiota in modulating hepatic immunity represent an emerging frontier with unexplored therapeutic implications. Continued advances in bioengineering, nanotechnology, and systems biology are expected to refine exosome-based therapies, offering novel, personalized strategies to improve outcomes for HCC patients.},
	doi = {10.1111/jgh.70245},
	pmid = {41623268 [Indexed for MEDLINE]}
}

@ARTICLE{10.3389/fimmu.2025.1754107,
	author = {Kang R and Sun A and Yang J and Chang L and Sun W and Kou F and Cheng Y},
	title = {Targeting the plasticity of intestinal neutrophils: bidirectional regulation strategies by natural products.},
	journal = {Front Immunol},
	year = {2026},
	abstract = {Historically, neutrophils have been regarded primarily as pro-inflammatory cells, yet recent advancements have revealed their phenotypic heterogeneity and functional plasticity with versatile immunophenotypes. Distinct subpopulations of neutrophils exhibit a functional duality, not only initiating and amplifying inflammation, but also actively promoting tissue restoration in diseases, such as inflammatory bowel disease (IBD), colorectal cancer (CRC) and intestinal infections. They contribute to the formation of a dynamic immune microenvironment in concert with the intestinal microbiota, epithelial cells, and other immune cell types. Current first-line therapies for enteric diseases often lack precision in modulating neutrophil functions. In contrast, natural products including alkaloids, polysaccharides, polyphenols, quinones, and glycosides, as well as microbiota-derived metabolites, exhibit distinct advantages for ability to achieve multi-targeted and bidirectional immunomodulation. These compounds target neutrophil activation, migration, neutrophil extracellular trap formation, cytokine release, oxidative stress, and energy metabolism etc. In this review, we systematically examine the heterogeneity and functional diversity of intestinal neutrophils, highlighting their interaction mechanisms with the surrounding microenvironment. Potential of natural products to modulate neutrophil functions via multi-target strategies has not been fully explored. Moreover, the review discusses novel precision therapeutic approaches based on neutrophil nanotechnology and engineered cell drug delivery. These cutting-edge technologies aim to enhance natural products delivery to inflammatory sites, provide controllable regulation of neutrophil function, and facilitate the degradation of pathological structures. Collectively, the study presents new research directions and theoretical frameworks for intervention of natural products in neutrophils of intestinal immune-related disorders, notably IBD and even CRC.},
	doi = {10.3389/fimmu.2025.1754107},
	pmid = {41601690 [Indexed for MEDLINE]},
	note = {PMC12833395}
}

@ARTICLE{10.3390/nu18020313,
	author = {Kogut Ł and Puchalski C, Katryńska D, Zaguła G},
	title = {The Multidirectional Biological Activity of Resveratrol: Molecular Mechanisms, Systemic Effects and Therapeutic Potential-A Review.},
	journal = {Nutrients},
	year = {2026},
	abstract = {Background/Objectives: Resveratrol is a multi-target polyphenolic stilbene widely studied for its antioxidant, anti-inflammatory, cardioprotective, hepatoprotective, neuroprotective, immunomodulatory and anticancer properties. This review summarizes current evidence on its molecular mechanisms, therapeutic potential, metabolic interactions and biological implications, with particular emphasis on bioavailability, signaling pathways and organ-specific actions. Methods: A comprehensive literature review was conducted focusing on recent in vitro, in vivo and clinical studies evaluating resveratrol's biochemical activity, molecular targets and physiological effects. Special attention was given to oxidative stress regulation, inflammatory signaling, mitochondrial function, metabolic pathways, gut microbiota interactions, and its influence on chronic diseases. Results: Resveratrol modulates several key signaling pathways including NF-κB, SIRT1, AMPK, MAPK, Nrf2 and PI3K/AKT/mTOR. It reduces oxidative stress, inhibits inflammatory cytokines, regulates apoptosis, improves mitochondrial performance, and activates endogenous antioxidant systems. The compound demonstrates protective effects in cardiovascular diseases, hepatic steatosis, neurodegenerative disorders, metabolic dysfunction, and various cancers through anti-inflammatory, anti-proliferative and anti-fibrotic mechanisms. Additionally, resveratrol beneficially alters gut microbiota composition and microbial metabolites, contributing to improved metabolic homeostasis. Despite high intestinal absorption, systemic bioavailability remains low; however, novel nanoformulations significantly enhance its stability and plasma concentrations. Conclusions: Resveratrol exhibits broad therapeutic potential driven by its capacity to regulate oxidative, inflammatory, metabolic and apoptotic pathways at multiple levels. Its pleiotropic activity makes it a promising candidate for prevention and complementary treatment of chronic diseases. Advances in delivery systems and microbiota-derived metabolites may further enhance its clinical applicability.},
	doi = {10.3390/nu18020313},
	pmid = {41599925 [Indexed for MEDLINE]},
	note = {PMC12845197}
}

@ARTICLE{10.1016/j.tjnut.2026.101362,
	author = {Mohammadi H and Ghoflchi S and Abass KS and Hosseini H and Sahebkar A},
	title = {Synergistic Therapeutic Potential of Curcumin and Metformin: a Multipathway Approach to Disease Management.},
	abstract = {Metformin, a first-line pharmacologic agent for type 2 diabetes, exerts its primary antidiabetic effects by suppressing hepatic gluconeogenesis via both AMP-activated protein kinases-dependent and -independent pathways. Beyond glycemic control, metformin exhibits pleiotropic benefits, including improved insulin sensitivity, modulation of gut microbiota, and protection against various metabolic, cardiovascular, renal, neurodegenerative, and inflammatory diseases. However, its clinical use is often limited by gastrointestinal side effects, vitamin B12 deficiency, and rare but serious complications such as lactic acidosis, highlighting the need for adjunctive strategies to enhance efficacy and reduce adverse effects. Curcumin, as a bioactive polyphenol, has garnered significant attention because of its extensive pharmacological activities and excellent safety profile. Curcumin modulates key intracellular signaling pathways, including nuclear factor-kappa B, mitogen-activated protein kinases, and phosphatidylinositol 3-kinase/protein kinase B, providing anti-inflammatory, antioxidant, anticancer, and metabolic regulatory effects. Nonetheless, its clinical application is constrained by poor bioavailability because of limited absorption, rapid metabolism, and systemic elimination. Recent evidence suggests that coadministration of metformin and curcumin yields synergistic therapeutic outcomes in diverse disease models. This combination improves glycemic control, mitigates oxidative stress and inflammation, and provides organ-protective effects, particularly in the liver, heart, and skin. Furthermore, it shows promise in cancer prevention and therapy, polycystic ovary syndrome management, and pain modulation, with enhanced outcomes when delivered via nanoparticle-based systems. This review aims to provide a comprehensive analysis of the combined therapeutic potential of metformin and curcumin across a spectrum of pathological conditions.},
	doi = {10.1016/j.tjnut.2026.101362},
	pmid = {41539435 [Indexed for MEDLINE]}
}

