@ARTICLE{10.2174/0118715206395910250816110857,
	author = {Singh H and Kumar R and Mazumder A},
	title = {Unlocking the Potential of Polysaccharides for the Treatment of Lung Cancer.},
	journal = {Anticancer Agents Med Chem},
	year = {2025},
	abstract = {BACKGROUND: Lung cancer remains a leading cause of cancer-related deaths worldwide, with its incidence continuing to rise. Despite advancements in clinical treatments, their effectiveness is often restricted, emphasizing the need for novel therapeutic strategies. Natural products have long been explored for drug development, and among them, polysaccharides have gained significant attention due to their biocompatibility, biodegradability, and multiple biological functions. METHODS: A comprehensive review examined contemporary research on the anticancer properties of natural polysaccharides, focusing specifically on their effects in lung cancer. The analysis included studies investigating their influence on cancer cell growth, immune system modulation, and therapeutic outcomes. Evidence from laboratory (in vitro), animal (in vivo), and clinical studies was evaluated to provide a comprehensive overview of their potential role in lung cancer management. RESULTS: Findings from recent studies indicate that polysaccharides can effectively inhibit the proliferation of lung cancer cells, thereby slowing tumor development. These compounds also appear to enhance immune responses by activating various immune cells and regulating cytokine production. Furthermore, polysaccharides have been shown to positively affect the gut microbiota, which may contribute to improved drug efficacy and a reduction in resistance to chemotherapy. DISCUSSION: The evidence suggests that natural polysaccharides exert multifaceted effects in the context of lung cancer treatment. Their ability to directly suppress tumor growth, modulate the immune system, and interact with the gut microbiome positions them as promising adjuncts to existing therapies. However, the precise molecular mechanisms underlying these effects are not yet fully understood, and variability in study designs warrants cautious interpretation of the results. CONCLUSION: Natural polysaccharides represent a promising complementary approach for lung cancer therapy, given their potential to inhibit tumor progression, enhance immune function, and improve the effectiveness of conventional drugs. Continued research is essential to fully elucidate their mechanisms of action and to translate these findings into effective clinical interventions.},
	doi = {10.2174/0118715206395910250816110857},
	pmid = {40908690}
}

@ARTICLE{10.3389/fimmu.2025.1642091,
	author = {He Q and Xiang L and Luo Y and Wang R and Zheng C and Gao Y and Yao H},
	title = {Tumor-associated macrophages in colon cancer immunotherapy: mechanisms, natural product interventions, and microenvironment remodeling.},
	journal = {Front Immunol},
	year = {2025},
	abstract = {Colon cancer persists as a major global health burden due to therapy resistance and metastasis, with tumor-associated macrophages (TAMs) in the microenvironment driving progression through immune evasion and angiogenesis. This review highlights plant-derived therapeutics targeting TAMs to disrupt protumor signaling. Key phytochemicals (e.g., Curcumin, Cucurbitacin B, Astragaloside IV) suppress M2 polarization via NF-κB/STAT3 inhibition, block VEGF/HIF-1α-mediated angiogenesis, and enhance antitumor immunity by downregulating PD-L1. Cannabidiol, Hydroxygenkwanin regulate TAM metabolism. Dietary agents like sulforaphane and β-glucans modulate TAM-gut microbiome crosstalk. Nanoparticle-encapsulated phytochemicals enhance TAM-targeted delivery, while clinical translation requires standardized phytopreparations and biomarker-guided trials. We propose integrating validated botanical adjuvants (e.g., Fucoidan for TLR4 inhibition, dihydroisotanshinone I for CCL2 suppression) with immunotherapies to remodel immunosuppressive niches. Phytotherapy offers a multifaceted strategy to overcome TAM-driven therapeutic barriers in colon cancer, emphasizing plant-based precision medicine to augment conventional treatments.},
	doi = {10.3389/fimmu.2025.1642091},
	pmid = {40873588 [Indexed for MEDLINE]},
	note = {PMC12378638}
}

@ARTICLE{10.1016/j.jconrel.2025.114124,
	author = {Miao Y and Wang K and Cao Y and Liu X and Zhang X and Mao J and Kang W and Cao C and Deng D},
	title = {Constructing natural phenolic acid mesopores to enhance chemotherapy and reduce accompanied intestinal damage.},
	journal = {J Control Release},
	year = {2025},
	abstract = {Mesoporous nanostructures have garnered significant attention as next-generation drug delivery systems due to their high specific surface area and tunable pore architectures. Incorporating bioactive natural products into these structures is expected to introduce novel functionalities and enhance therapeutic performance. In this study, we focus on the construction of mesoporous rosmarinic acid (MP-RA), a phenolic acid-based nanostructure, and its molecular self-assembly mechanism, as well as its application in oral chemotherapy through a Xylan-Irinotecan (Xylan-IR) coating strategy. Results reveal that the initial oxidative aggregation of rosmarinic acid leads to the formation of an active self-template, with enhanced hydrogen bonding and π-π stacking interactions driving the ordered assembly into mesoporous structures. The resulting MP-RA exhibits a porous architecture enriched with active sites derived from the parent bioactive molecules, enabling efficient encapsulation of irinotecan (IR). Moreover, stable integration with the Xylan-IR coating ensures protection through gastric transit, facilitates targeted delivery, and enhances modulation of the gut microbiota. These combined effects improve anticancer efficacy and reduce chemotherapy-induced gastrointestinal inflammation. Overall, this study demonstrates the potential of self-assembled, small-molecule-based mesoporous structures in advancing natural product-driven drug delivery systems toward broader clinical applications.},
	doi = {10.1016/j.jconrel.2025.114124},
	pmid = {40818716 [Indexed for MEDLINE]}
}

@ARTICLE{10.1016/j.phymed.2025.157030,
	author = {Zhou W and Asif A and Situ C and Wang J and Hao H},
	title = {Multiple target and regulatory pathways of berberine.},
	journal = {Phytomedicine},
	year = {2025},
	abstract = {BACKGROUND: Berberine (BBR), a widely used monomer in traditional Chinese medicine, well-known for its extensive pharmacological activities against tumors, neurological disorders, and cardiovascular disease. These effects are mediated through the regulation of multiple molecular targets and signaling pathways, including the MAPK, TLR4/NF-κB, PI3K/AKT, and AMPK/mTOR. In addition, BBR demonstrate potent antimicrobial activity by reducing pathogen invasiveness, disrupting biofilms integrity, preventing the formation of macromolecules, and interfering with metabolic processes. More, BBR can modulate the gut microbiome and exhibit an effective treatment for metabolic disorders such as diabetes mellitus. PURPOSE: The goal of this review is to present a current summary of the molecular processes that underlie BBR's action, discussing BBR interactions with novel factors, examining current knowledge on BBR side effect and nano-carrier applications, offering new perspective on expanding its therapeutic use. Further is required to identify novel targets of berberine and to investigate its potential for new therapeutic applications. METHODS: The review adhered to the Preferred Reporting Items for Systematic Reviews and Meta-Analyses (PRISMA) guidelines. Data were organized into tabular and narrative formats. Structural formulae of compounds were created using ChemDraw Professional 22.0 software, while botanical information was sourced from the Flora of China (www.iplant.cn). The keyword "Berberine" was used to search databases, including ScienceDirect, PubMed, CNKI, and Web of Science, covering publications from 1970 to 2024. To ensure comprehensive data collection, additional searches were conducted using Connected Papers, Springer Search, Baidu Scholar, Google Scholar, and other databases. Keywords such as "toxicology," "traditional uses," "molecular mechanism," "pharmacology," and "chemical compounds" were applied to further refine and analyze the collected information. RESULTS: Berberine exerts potent antibacterial, anti-inflammatory, and therapeutic effects in cardiovascular, neurological, metabolic, and tumor-related conditions by modulating key intracellular signaling pathways (e.g., AMPK/mTOR, PI3K/AKT, TLR4/NF-κB). It also impacts gut flora, offering new treatment avenues for gastrointestinal diseases, diabetes, and related renal disorders. Despite its clinical efficacy, berberine's low oral bioavailability and the complexity of its mechanisms and safety profile highlight the need for further research to fully unlock its therapeutic potential. CONCLUSION: This study summarises the methods by which berberine heals a number of prevalent conditions and elaborates on the relationship between berberine and illnesses. Furthermore, it discusses the application of berberine nanofomulations in treating diseases. Future research on berberine should explore its potential in treating rare diseases, mental health disorders, immune conditions, neurodegenerative diseases, metabolic disorders, and cancer, while enhancing drug delivery systems and investigating its epigenetic effects.},
	doi = {10.1016/j.phymed.2025.157030},
	pmid = {40763599 [Indexed for MEDLINE]}
}

@ARTICLE{10.1021/acsnano.5c01158,
	author = {Liu Q and Wu Y and Fan Q and Liu J and Chen Y and He Y and Wei W and Zhang H and Zhao Y and He Y and Du X and Guo J},
	title = {Oral Nanoarmored Live Bacterial Biotherapeutics Bearing Polyphenol-Based Supraparticles Enhance Chemotherapy via Reestablishing Immuno-Oncology-Microbiome Axis.},
	journal = {ACS Nano},
	year = {2025},
	abstract = {The immuno-oncology-microbiome (IOM) axis, referring to the gut microbiota-regulated immune interactions on the tumor microenvironment and systemic immunity, is essential for cancer therapies. However, the cytotoxicity of chemotherapeutic agents (Chemos) disrupts the gut microbiota- and gut microbiota-manipulated IOM axis, further diminishing the therapeutic efficacy. Here, we developed oral nanoarmored live bacterial biotherapeutics (supraLBT), to reshape the tumor microenvironment and enhance chemotherapy via reestablishing the IOM axis. The cyto-adhesive polyphenol-based supraparticles, made from green tea polyphenol and food-grade milk protein, attached on microbes (Escherichia coli Nissle1917, EcN) resisted a range of clinically relevant Chemos via phenolic-mediated noncovalent interactions, enhancing supraLBT survival by 27-fold compared with bare EcN. SupraLBT restored the intestinal microbiota and the disrupted IOM axis, thereby reducing the infiltration of regulatory T cells, increasing the recruitment of cytotoxic CD8+ T cells to the tumor bed, and further inhibiting tumor proliferation and demonstrating enhanced systemic immune responses. Notably, oral supraLBT combined with chemotherapy (doxorubicin) exhibited 2.35-fold greater tumor regression than that of doxorubicin alone, indicating that oral supraLBT can enhance the chemotherapeutic effect. Further investigations revealed that supraLBT reprogrammed the immune tumor microenvironment by upregulating antitumor cytokines and altering the gut microbial composition. Given the intricate interplay between gut microbiota, host immune system, and tumor microenvironment, this work presents a facile and biomaterial-engineered microorganism-based strategy to enhance the synergistic immuno-chemotherapy effects.},
	doi = {10.1021/acsnano.5c01158},
	pmid = {40566930 [Indexed for MEDLINE]}
}

@ARTICLE{10.3390/ijms26125521,
	author = {Jannati S and Patel A and Patnaik R and Banerjee Y},
	title = {Oleocanthal as a Multifunctional Anti-Cancer Agent: Mechanistic Insights, Advanced Delivery Strategies, and Synergies for Precision Oncology.},
	journal = {Int J Mol Sci},
	year = {2025},
	abstract = {Oleocanthal (OC), a secoiridoid phenolic compound exclusive to extra virgin olive oil (EVOO), has emerged as a promising nutraceutical with multifaceted anti-cancer properties. Despite its well-characterized anti-inflammatory and antioxidant effects, the mechanistic breadth and translational potential of OC in oncology remain underexplored and fragmented across the literature. This comprehensive review synthesizes and critically analyzes recent advances in the molecular, pharmacological, and translational landscape of OC's anti-cancer activities, providing an integrative framework to bridge preclinical evidence with future clinical application. We delineate the pleiotropic mechanisms by which OC modulates cancer hallmarks, including lysosomal membrane permeabilization (LMP)-mediated apoptosis, the inhibition of key oncogenic signaling pathways (c-MET/STAT3, PAR-2/TNF-α, COX-2/mPGES-1), the suppression of epithelial-to-mesenchymal transition (EMT), angiogenesis, and metabolic reprogramming. Furthermore, this review uniquely highlights the emerging role of OC in modulating drug resistance mechanisms by downregulating efflux transporters and sensitizing tumors to chemotherapy, targeted therapies, and immunotherapies. We also examine OC's bidirectional interaction with gut microbiota, underscoring its systemic immunometabolic effects. A major unmet need addressed by this review is the lack of consolidated knowledge regarding OC's pharmacokinetic limitations and drug-drug interaction potential in the context of polypharmacy in oncology. We provide an in-depth analysis of OC's poor bioavailability, extensive first-pass metabolism, and pharmacogenomic interactions, and systematically compile preclinical evidence on advanced delivery platforms-including nanocarriers, microneedle systems, and peptide-drug conjugates-designed to overcome these barriers. By critically evaluating the mechanistic, pharmacological, and translational dimensions of OC, this review advances the field beyond isolated mechanistic studies and offers a strategic blueprint for its integration into precision oncology. It also identifies key research gaps and outlines the future directions necessary to transition OC from a nutraceutical of dietary interest to a viable adjunctive therapeutic agent in cancer treatment.},
	doi = {10.3390/ijms26125521},
	pmid = {40564985 [Indexed for MEDLINE]},
	note = {PMC12193433}
}

@ARTICLE{10.3389/fnut.2025.1606289,
	author = {Akanyibah FA and He C and Wang X and Wang B and Mao F},
	title = {The role of plant-based dietary compounds in gut microbiota modulation in inflammatory bowel disease.},
	abstract = {IBD, which includes Crohn's and ulcerative colitis, is associated with gut microbiota dysbiosis. The dysbiotic environment results in an elevation of harmful microbiota and a diminution of advantageous microbiota, leading to IBD. Interestingly, plant-based dietary compounds consisting of dietary fibers and polyphenols have demonstrated promise to be safe and successful in IBD treatment, with studies revealing that they can improve dysbiosis, increase anti-inflammatory cytokines, decrease pro-inflammatory cytokines, lower oxidative stress, and improve barrier function. Plant-based dietary compounds have shown potential to reduce IBD by regulating signaling pathways such as TGF-β/Smad, TRL-4/NF-κB/MAPK, TLR2-NF-κB, autophagy, pyroptosis, glycolysis/gluconeogenesis and amino acid metabolism, Nrf-2/HO-1, microbiota-macrophage-arginine metabolism, and bile acid metabolism. Additionally, they assist in forming short-chain fatty acids and other metabolites, which help regulate immune cells to alleviate IBD. Recent research indicates that dietary compounds, either as nanoparticles or encapsulated in nanoparticles, have shown potential in effectively treating IBD. Despite the beneficial role of plant-based dietary compounds, other studies have shown detrimental effects such as cancer promotion and exacerbation of immune responses. Therefore, this will help clinicians/individuals to plan their nutrition to prevent IBD exacerbation. This review highlights the microbiota signatures linked to IBD and examines the impact of gut dysbiosis on IBD. It also provides a comprehensive discussion of how plant-based dietary compounds can influence the modulation of dysbiotic gut microbiota in IBD. Plant-based dietary compounds hold potential for treating IBD.},
	doi = {10.3389/fnut.2025.1606289},
	pmid = {40521353},
	note = {PMC12163340}
}

