@ARTICLE{10.1016/j.ijbiomac.2025.145132,
	author = {Zhang N and Xie W and Liu W and Ma L and Man S},
	title = {Preparation of curcumin loaded carboxymethyl chitosan nanoparticles and their anti-hepatoma effects through liver-gut circulation.},
	journal = {Int J Biol Macromol},
	year = {2025},
	abstract = {Curcumin, a natural compound extracted from the rhizomes of Curcuma longa, has gained much attention due to its high food safety profile and broad biological activities, especial for anti-cancer activities. However, its clinical application is limited by poor bioavailability. In this study, we develop liver-targeted carboxymethyl chitosan (CMCS) nanoparticles named curcumin (CUR)-loaded dual ligand nanoparticles (DL NPs). CMCS is modified with deoxycholic acid (DCA), lactobionic acid (LA) and glycyrrhetinic acid (GA), which are regarded as safe common food. Transmission electron microscopy, 1H NMR and Fourier-transform infrared spectroscopy are used for the characterization of DL NPs. As a result, CMCS possesses hydrophilic groups, and is pH-sensitive. DCA acts as the hydrophobic group and promotes the formation of self-assembled nanoparticles. LA and GA are used as the liver specific delivery of CUR. The drug-loaded DL NPs exhibit stronger cell internalization, and anticancer efficacies than the free CUR. Additionally, DL NPs improved the gut dysbiosis, and increased the abundance of Lachnospiraceae_ NK4A136_group and the content of butyric acid, which further increased the expression of caspase 3 and induced apoptosis. Overall, it's proved that DL NPs would become promising pharmaceutical formulations for selectively overcoming hepatocellular carcinoma, with great potential for clinical applications.},
	doi = {10.1016/j.ijbiomac.2025.145132},
	pmid = {40499859 [Indexed for MEDLINE]}
}

@ARTICLE{10.1186/s13020-025-01124-y,
	author = {Cui D and Zhang C and Zhang L and Zheng J and Wang J and He L and Jin H and Kang Q and Zhang Y and Li N and Sun Z and Zheng W and Wei J and Zhang S and Feng Y and Tan W and Zhong Z},
	title = {Natural anti-cancer products: insights from herbal medicine.},
	journal = {Chin Med},
	year = {2025},
	abstract = {Herbal medicine exhibits a broad spectrum of potent anti-cancer properties, including the enhancement of tumor immune responses, reversal of multidrug resistance, regulation of autophagy and ferroptosis, as well as anti-proliferative, pro-apoptotic, and anti-metastatic effects. This review systematically explores recent advances (primarily documented since 2019) in research on key anti-cancer compounds derived from herbal medicine, such as apigenin, artemisinin, berberine, curcumin, emodin, epigallocatechin gallate (EGCG), ginsenosides, icariin, resveratrol, silibinin, triptolide, and ursolic acid (UA). These studies were sourced from scientific databases, including PubMed, Web of Science, Medline, Scopus, and Clinical Trials. The review focuses on the significant role that these natural products play in modern oncology, exploring their efficacy, mechanisms of action, and the challenges and prospects of integrating them into conventional cancer therapies. Furthermore, it highlights cutting-edge approaches in cancer research, such as the utilization of gut microbiota, omics technologies, synthetic derivatives, and advanced drug delivery systems (DDS). This review underscores the potential of these natural products to advance the development of novel anti-cancer treatments and support contemporary medicine. Additionally, recent multi-omics findings reveal how these compounds reshape transcriptional and metabolic networks, further broadening their therapeutic scope. Many natural products exhibit synergy with first-line chemotherapies or targeted therapies, thereby enhancing treatment efficacy and reducing side effects. Advanced nano-formulations and antibody-drug conjugates have also substantially improved their bioavailability, making them promising candidates for future translational research.},
	doi = {10.1186/s13020-025-01124-y},
	pmid = {40490812},
	note = {PMC12147394}
}

@ARTICLE{10.1186/s12943-025-02305-x,
	author = {Zhang M and Liu C and Tu J and Tang M and Ashrafizadeh M and Nabavi N and Sethi G and Zhao P and Liu S},
	title = {Advances in cancer immunotherapy: historical perspectives, current developments, and future directions.},
	journal = {Mol Cancer},
	year = {2025},
	abstract = {Cancer immunotherapy, encompassing both experimental and standard-of-care therapies, has emerged as a promising approach to harnessing the immune system for tumor suppression. Experimental strategies, including novel immunotherapies and preclinical models, are actively being explored, while established treatments, such as immune checkpoint inhibitors (ICIs), are widely implemented in clinical settings. This comprehensive review examines the historical evolution, underlying mechanisms, and diverse strategies of cancer immunotherapy, highlighting both its clinical applications and ongoing preclinical advancements. The review delves into the essential components of anticancer immunity, including dendritic cell activation, T cell priming, and immune surveillance, while addressing the challenges posed by immune evasion mechanisms. Key immunotherapeutic strategies, such as cancer vaccines, oncolytic viruses, adoptive cell transfer, and ICIs, are discussed in detail. Additionally, the role of nanotechnology, cytokines, chemokines, and adjuvants in enhancing the precision and efficacy of immunotherapies were explored. Combination therapies, particularly those integrating immunotherapy with radiotherapy or chemotherapy, exhibit synergistic potential but necessitate careful management to reduce side effects. Emerging factors influencing immunotherapy outcomes, including tumor heterogeneity, gut microbiota composition, and genomic and epigenetic modifications, are also examined. Furthermore, the molecular mechanisms underlying immune evasion and therapeutic resistance are analyzed, with a focus on the contributions of noncoding RNAs and epigenetic alterations, along with innovative intervention strategies. This review emphasizes recent preclinical and clinical advancements, with particular attention to biomarker-driven approaches aimed at optimizing patient prognosis. Challenges such as immunotherapy-related toxicity, limited efficacy in solid tumors, and production constraints are highlighted as critical areas for future research. Advancements in personalized therapies and novel delivery systems are proposed as avenues to enhance treatment effectiveness and accessibility. By incorporating insights from multiple disciplines, this review aims to deepen the understanding and application of cancer immunotherapy, ultimately fostering more effective and widely accessible therapeutic solutions.},
	doi = {10.1186/s12943-025-02305-x},
	pmid = {40336045 [Indexed for MEDLINE]},
	note = {PMC12057291}
}

@ARTICLE{10.1016/j.phrs.2025.107742,
	author = {Chen G and Zhang C and Zou J and Zhou Z and Zhang J and Yan Y and Liang Y and Tang G and Chen G and Xu X and Wang N and Feng Y},
	title = {Coptidis rhizoma and berberine as anti-cancer drugs: A 10-year updates and future perspectives.},
	journal = {Pharmacol Res},
	year = {2025},
	abstract = {Cancer continues to be among the most substantial health challenges globally. Among various natural compounds, berberine, an isoquinoline alkaloid obtained from Coptidis Rhizoma, has garnered considerable attention for its broad-spectrum biological activities, including anti-inflammatory, antioxidant, anti-diabetic, anti-obesity, and anti-microbial activities. Furthermore, berberine exhibits a broad spectrum of anti-cancer efficacy against various malignancies, such as ovarian, breast, lung, gastric, hepatic, colorectal, cervical, and prostate cancers. Its anti-cancer mechanisms are multifaceted, encompassing the inhibition of cancer cell proliferation, the prevention of metastasis, the induction of apoptosis, the facilitation of autophagy, the modulation of the tumor microenvironment and gut microbiota, and the enhancement of the efficacy of conventional therapeutic strategies. This paper offers an exhaustive overview of the cancer-fighting characteristics of Coptidis Rhizoma and berberine, while also exploring recent developments in nanotechnology aimed at enhancing the bioavailability of berberine. Furthermore, the side effects and safety of berberine are addressed as well. The potential role of artificial intelligence in optimizing berberine's therapeutic applications is also highlighted. This paper provides precious perspectives on the prospective application of Coptidis Rhizoma and berberine in the prevention and management of cancer.},
	doi = {10.1016/j.phrs.2025.107742},
	pmid = {40258505 [Indexed for MEDLINE]}
}

@ARTICLE{10.1002/mnfr.70011,
	author = {Oriol-Caballo M and Moreno-Murciano MP, López-Blanch R and Estrela JM and Obrador E},
	title = {Polyphenols: Potential Applications in Cancer Therapy.},
	journal = {Mol Nutr Food Res},
	year = {2025},
	abstract = {Polyphenols (PFs) are compounds found in fruits and vegetables, known for their health-related benefits, mainly including antioxidant, antiinflammatory, and anticancer properties. However, their efficacy is limited by poor bioavailability due to issues like low solubility, rapid metabolism, and extensive excretion. Thus, research has focused on improving delivery systems, such as, for example, nanoparticles, hydrogels, cocrystals, or conjugation with carrier molecules, which may protect PFs from degradation, improve solubility, and/or facilitate targeted delivery to cancer cells. PFs are promising in modulating cancer-related pathways like cell proliferation and death, or metastatic invasion, though their translation to patients is hindered by bioavailability and complex cancer mechanisms. This review analyzes factors that affect PF bioavailability, evidences of in vivo effects in animal models and their mechanisms, results from clinical trials, and strategies to enhance bioavailability. The idea that PFs need to directly interact with the cancer cell is challenged. Future research aims to optimize delivery systems, combine PFs with standard treatments, and explore their epigenetic effects, modulation of the tumor microenvironment, and interactions with gut microbiota. Advances in personalized medicine and structural modifications to improve stability and absorption could further enhance PF anticancer potential. Despite challenges, PFs remain a promising avenue for complementary oncotherapy solutions.},
	doi = {10.1002/mnfr.70011},
	pmid = {40143714 [Indexed for MEDLINE]}
}

@ARTICLE{10.3390/ijms26062593,
	author = {Kang HS and Lim HK and Jang WY and Cho JY},
	title = {Anti-Colorectal Cancer Activity of Panax and Its Active Components, Ginsenosides: A Review.},
	journal = {Int J Mol Sci},
	year = {2025},
	abstract = {Colorectal cancer (CRC) poses a significant health burden worldwide and necessitates novel treatment approaches with fewer side effects than conventional chemotherapy. Many natural compounds have been tested as possible cancer treatments. Plants in the genus Panax have been widely studied due to their therapeutic potential for various diseases such as inflammatory disorders and cancers. Extracts from plants of genus Panax activate upstream signals, including those related to autophagy and the generation of reactive oxygen species, to induce intrinsic apoptosis in CRC cells. The root extract of Panax notoginseng (P. notoginseng) regulated the gut microbiota to enhance the T-cell-induced immune response against CRC. Protopanaxadiol (PPD)-type ginsenosides, especially Rh2, Rg3, Rb1, and Rb2, significantly reduced proliferation of CRC cells and tumor size in a xenograft mouse model, as well as targeting programmed death (PD)-1 to block the immune checkpoint of CRC cells. Moreover, modified nanocarriers with ginsenosides upregulated drug efficacy, showing that ginsenosides can also be utilized as drug carriers. An increasing body of studies has demonstrated the potential of the genus Panax in curing CRC. Ginsenosides are promising active compounds in the genus Panax, which can also support the activity of conventional cancer therapies.},
	doi = {10.3390/ijms26062593},
	pmid = {40141242 [Indexed for MEDLINE]},
	note = {PMC11941759}
}

@ARTICLE{10.1016/j.ijbiomac.2025.142327,
	author = {Jia B and Yang W and Li H and Chang G and Zhang X and Zhang N and Wang S and Wei J and Li X and Gao W and Guo L},
	title = {Ophiopogonis Radix fructan-selenium nanoparticles for dual amelioration of ulcerative colitis and anti-colon cancer.},
	journal = {Int J Biol Macromol},
	year = {2025},
	abstract = {Fructans demonstrate significant potential in preclinical models for treating inflammatory bowel disease and colorectal cancer by modulating gut microbiota homeostasis. In this research, ORP-SeNPs were prepared through a redox method. Their roles as colon-targeted delivery carriers and stabilizers were examined for treating inflammatory bowel disease and colorectal cancer. ORP-SeNPs showed potent scavenging activity against ABTS· and DPPH· radicals and dose-dependently inhibited colon cancer Caco-2 cell proliferation by arresting growth in the S phase. Moreover, ORP-SeNPs significantly alleviated intestinal inflammation by modulating inflammatory cytokine homeostasis, reducing oxidative stress, repairing the intestinal barrier, and suppressing NF-κB/STAT-3 pathway activation. This study establishes a theoretical foundation for employing mixed fructans as drug carriers to treat inflammatory bowel disease and colorectal cancer, extending the therapeutic applications of Ophiopogonis Radix in bowel disorders.},
	doi = {10.1016/j.ijbiomac.2025.142327},
	pmid = {40118427 [Indexed for MEDLINE]}
}

@ARTICLE{10.3390/nu17050744,
	author = {Khandwal D and Patel S and Pandey AK and Mishra A},
	title = {A Comprehensive, Analytical Narrative Review of Polysaccharides from the Red Seaweed Gracilaria: Pharmaceutical Applications and Mechanistic Insights for Human Health.},
	journal = {Nutrients},
	year = {2025},
	abstract = {Gracilaria species, a widely distributed genus of red macroalgae, have gathered significant attention for their diverse medical applications attributable to their bioactive sulphated polysaccharides (SPs). This review examines the global narrative of various Gracilaria SP applications in terms of their therapeutic potential and mechanistic insights into the use of these SPs against a range of medical conditions, including cancer, inflammation, neurodegenerative disorders, diabetes, and immune dysfunctions. SPs extracted from G. lemaneiformis and G. fisheri have demonstrated potent anti-tumour activities by inducing apoptosis through various mechanisms, including the upregulation of CD8+ T cells and IL-2, inhibition of EGFR/MAPK/ERK signalling pathways, and activation of the Fas/FasL pathway. Selenium nanoparticles (SeNPs) conjugated with SPs further enhanced the targeted delivery and efficacy of these SPs against glioblastoma by the downregulation of ROS followed by the activation of p53, MAPK, and AKT pathways. The anti-inflammatory properties of SPs are evidenced by key suppressive inflammatory markers like NO, TNF-α, IL-1β, and IL-6 in mutant rodent models. SPs from G. cornea and G. birdiae effectively reduce neutrophil migration and vascular permeability, offering potential treatments for acute inflammation and conditions such as colitis by modulating pathways involving COX-2 and NF-κB. Neuroprotective effects by SPs (from G. cornea and G. gracili) studied in 6-OHDA-induced rats, which mitigate oxidative stress and enhance neuronal cell viability, facilitate the management of neurodegenerative diseases like Parkinson's and Alzheimer's. Regarding the hypoglycaemic effect, SPs from G. lemaneiformis exhibit a glucose-modulating response by improving insulin regulation, inhibiting α-amylase activity, repairing pancreatic β-cells, and modulating lipid metabolism. Moreover, immunomodulatory activities of Gracilaria-derived SPs include the stimulation of macrophages, T-cell proliferation, and cytokine production, underscoring their potential as functional food and immunotherapeutic agents. Recently, Gracilaria-derived SPs have been found to modulate gut microbiota, promote SCFA production, and enhance gut microbials, suggesting their potential as prebiotic agents (G. rubra and G. lemaneiformis). This review highlights the multifaceted medical applications of Gracilaria sulphated polysaccharides, providing detailed mechanistic insights and suggesting avenues for future clinical translation and therapeutic innovations.},
	doi = {10.3390/nu17050744},
	pmid = {40077614 [Indexed for MEDLINE]},
	note = {PMC11901860}
}

@ARTICLE{10.3390/cimb47020126,
	author = {Liu F and Guo C and Liu X and Gu Z and Zou W and Tang X and Tang J},
	title = {Luteolin in Inflammatory Bowel Disease and Colorectal Cancer: A Disease Continuum Perspective.},
	journal = {Curr Issues Mol Biol},
	year = {2025},
	abstract = {Inflammatory bowel disease (IBD) is a chronic intestinal inflammatory condition that may progress to colorectal cancer (CRC), presenting significant challenges to global health. With shifts in lifestyle, the incidence of both conditions continues to rise, underscoring the urgent need for effective treatments. While traditional therapies can be effective, their high recurrence rates and associated adverse reactions limit their broader application. Luteolin, a flavonoid derived from natural plants, has emerged as a promising focus in both IBD and CRC research due to its multi-target therapeutic potential. This article reviews the molecular mechanisms and signaling pathways through which luteolin regulates immune cell differentiation, mitigates inflammation and oxidative stress, modulates gut microbiota, and restores intestinal mucosal barrier function in IBD. In the context of CRC, luteolin demonstrates significant anti-tumor effects by inhibiting cancer cell proliferation, inducing apoptosis, and suppressing cell migration and invasion. Notably, luteolin has demonstrated significant improvements in IBD symptoms by influencing the differentiation of T cell subsets, decreasing the expression of inflammatory mediators, activating antioxidant pathways, and enhancing the structure of gut microbiota. Furthermore, advancements in formulation technology, such as the use of polymer micelles and responsive nanoparticles, have greatly improved the bioavailability and efficacy of luteolin. However, further investigation is needed to address the bioavailability and potential toxicity of luteolin, particularly in the critical transition from IBD to CRC. This article emphasizes the potential of luteolin in the treatment of IBD and CRC and anticipates its promising prospects for future clinical applications as a natural therapeutic agent.},
	doi = {10.3390/cimb47020126},
	pmid = {39996847},
	note = {PMC11853781}
}

@ARTICLE{10.1016/j.phymed.2025.156376,
	author = {Li Y and Shao S and Zhou Y and Wang Y and Zheng W and Wang H and Wang M and Jin K and Zou H and Mou X},
	title = {Oral administration of Folium Artemisiae Argyi-derived exosome-like nanovesicles can improve ulcerative colitis by regulating intestinal microorganisms.},
	journal = {Phytomedicine},
	year = {2025},
	abstract = {BACKGROUND: Ulcerative colitis (UC), an inflammatory disease characterized by intestinal barrier dysfunction, poses significant challenges because of the toxicity and adverse effects commonly associated with conventional therapies. Safer and more efficacious treatment strategies are needed. PURPOSE: The purpose of this study was to treat UC with Folium Artemisiae Argyi exosome-like nanovesicles (FAELNs) and to explore its related mechanism to provide a safer and more effective means for the treatment of ulcerative colitis. METHODS: We established an in vivo model of acute UC in mice and an in vitro inflammatory model using HT-29 human colorectal cancer cells. To evaluate the therapeutic effect of FAELNs on UC, we adopted various proxies, including changes in body weight and disease activity index (DAI) of mice, and measurement of colon length. The concentrations of myeloperoxide, interleukin (IL-1β), IL-6, tumor necrosis factor-alpha, monocyte chemoattractant protein-1, and interferon-gamma in sera of mice were detected by ELISA. Immunohistochemistry, hematoxylin and eosin staining, and Alyssin blue staining were performed. The effect of HT-29 cells on oxidative stress was detected using an active oxygen probe, diacetyldichlorofluorescein, and flow cytometry. Western blotting was performed to detect the expression levels of Bax and Bcl-2 in HT-29 cells treated with FAELNs. The effects of FAELNs on IL-6 and IL-1β were detected by fluorescence quantitative PCR. Fecal 16S bacteria were detected, and the role of FAELNs was verified by α diversity and β diversity analyses, principal component analysis, species distribution, and function prediction. For microRNA sequencing of FAELNs, Gene Ontology and Kyoto Encyclopedia of Genes and Genomes analyses were performed. To detect the metabolic and lipid groups of FAELNs, the components were identified and a pharmacological network was constructed to explore the related mechanisms and diseases. RESULTS: FAELNs effectively alleviated the pathogenesis of UC induced by dextran sodium sulfate in animal models, restoring the integrity of the intestinal barrier and reversing an imbalance of the intestinal microbiota. CONCLUSION: Our findings demonstrate the therapeutic potential of FAELNs in UC management, highlighting their scalability for mass production and encouraging prospects for clinical transformation.},
	doi = {10.1016/j.phymed.2025.156376},
	pmid = {39813847 [Indexed for MEDLINE]}
}

@ARTICLE{10.1016/j.canlet.2025.217459,
	author = {Bai X and Liu B and Fan D and Lu Y and Zhao X},
	title = {Modulating the gut microbiota: A novel perspective in colorectal cancer treatment.},
	journal = {Cancer Lett},
	year = {2025},
	abstract = {Colorectal cancer (CRC), the second leading cause of cancer-related deaths worldwide, is intricately linked to the dysregulation of the gut microbiota. Manipulating the gut microbiota has emerged as a novel strategy for the prevention and treatment of CRC. Natural products, a pivotal source in new drug discovery, have shown promise in recent research as regulators of the gut microbiota, offering potential applications in the prevention and treatment of CRC. In this work, commencing with a focus on the gut microbiota, we first elucidate the latest research on the intricate relationship between the gut microbiota and CRC. Additionally, we explore the impact of the gut microbiota on immunotherapy and chemotherapy treatments for CRC. Subsequently, we review the latest research findings on the regulation of the gut microbiota for CRC prevention through various mechanisms by natural products. These mechanisms include promoting the growth of beneficial bacteria, eradicating harmful bacteria, and enhancing the synthesis of beneficial metabolites. Furthermore, we summarize the advancements in research on natural products that alleviate chemotherapy toxicity and enhance the efficacy of immunotherapy by modulating the gut microbiota. Ultimately, we aspire to leverage advancements in nanomedicine and multiomics technologies to gain a deeper understanding of the mechanisms by which natural products regulate the gut microbiota. This work leverages gut microbiota as a focal point, aiming to offer new perspectives for developing novel natural products for colorectal cancer prevention and treatment.},
	doi = {10.1016/j.canlet.2025.217459},
	pmid = {39805389 [Indexed for MEDLINE]}
}

@ARTICLE{10.3390/foods13244073,
	author = {Long Y and Ji H and Yang J and Ji H and Dai K and Ding W and Zheng G and Yu J},
	title = {Immunoregulatory Effects of Codonopsis pilosula Polysaccharide Modified Selenium Nanoparticles on H22 Tumor-Bearing Mice.},
	journal = {Foods},
	year = {2024},
	abstract = {Codonopsis pilosula polysaccharide (CPP) and rare element selenium (Se) have been proved to exert various biological activities, and our previous study demonstrated that selenium nanoparticles modified with CPP (CPP-SeNPs) possessed significantly enhanced tumor cytotoxicity in vitro. This study aimed to investigated the inhibitory effects of CPP-SeNPs complex on H22 solid tumors via immune enhancement. In this study, the H22 tumor-bearing mice model was constructed, and the potential mechanisms of CPP-SeNPs antitumor effects were further explored by evaluating cytokines expression levels, immune cells activities and tumor cells apoptotic indicators in each group. The results demonstrated that CPP-SeNPs effectively exerted dose-dependent protective effects on the immune organs of tumor-bearing mice in vivo, leading to increase in peripheral white blood cell counts and inhibition of solid tumor growth with inhibitory rate of 47.18% in high-dose group (1.5 mg/kg). Furthermore, CPP-SeNPs treatment significantly elevated the levels of TNF-α, IFN-γ, and IL-2 in mice sera, enhanced NK cell cytotoxicity, augmented macrophage phagocytosis capacity, as well as increased both the amounts and proliferation activity of lymphocyte subsets. CPP-SeNPs improved the immune system's ability to clear tumor cells by up-regulating Bax expression while down-regulating Bcl-2 expression within solid tumors, indicating the potential activation of mitochondrial apoptosis pathway. Therefore, CPP-SeNPs administration can effectively inhibit tumor growth by enhancing immune response in tumor-bearing mice, which might be relevant to the regulation of gut microbiota short-chain fatty acids metabolisms. These findings could provide theoretical support and data foundation for further development of CPP-SeNPs as functional food and drug adjuvants.},
	doi = {10.3390/foods13244073},
	pmid = {39767013},
	note = {PMC11675135}
}

@ARTICLE{10.1016/j.phymed.2024.156352,
	author = {Abdullah and Ahmad N and Xiao J and Tian W and Khan NU and Hussain M and Ahsan HM and Hamed YS and Zhong H and Guan R},
	title = {Gingerols: Preparation, encapsulation, and bioactivities focusing gut microbiome modulation and attenuation of disease symptoms.},
	journal = {Phytomedicine},
	year = {2025},
	abstract = {BACKGROUND: Gut dysbiosis, chronic diseases, and microbial recurrent infections concerns have driven the researchers to explore phytochemicals from medicinal and food homologous plants to modulate gut microbiota, mitigate diseases, and inhibit pathogens. Gingerols have attracted attention as therapeutic agents due to their diverse biological activities like gut microbiome regulation, gastro-protective, anti-inflammatory, anti-microbial, and anti-oxidative effects. PURPOSE: This review aimed to summarize the gingerols health-promoting potential, specifically focusing on the regulation of gut microbiome, attenuation of disease symptoms, mechanisms of action, and signaling pathways involved. METHOD: Research findings from experimental and clinical studies have been summarized regarding gingerols effects on the modulation of gut microbiome and its metabolites, and attenuation of disease symptoms. RESULTS: Gingerols are phenolic compounds characterized by a common 3-methoxy-4-hydroxyphenyl moiety in their chemical structures, and further divided into different gingerol types, including gingerols (major), shogaols, paradols, gingerdiols, gingerdiones, and zingerones (minor). Advanced extraction techniques (e.g., ionic liquid-based-, enzyme-assisted-, microwave-assisted-, pressurized liquid-, ultrasound-assisted-, and supercritical fluid extractions) were reported as optimal alternatives to conventional methods for gingerols extraction. Research studies reported that gingerols positively modulated the composition of gut microbiome that helped to combat disease symptoms (e.g., obesity by decreasing weight gain- (Lactobacillus reuteri and Lachnospiraceae) and increasing weight loss associated-bacteria (Akkermansia, Muribaculaceae, and Alloprevotella). Gingerols intervention also ameliorated ulcerative colitis by increasing relative abundance of the beneficial bacteria (Akkermansia, Lachnospiraceae NK4A136, and Muribaculaceae_norank), and decreasing pathogenic microorganisms (Bacteroides, Parabacteroides, and Desulfovibrio). Emerging delivery systems (e.g., microcapsules, nanoparticles, nanostructured lipid carriers, nanoemulsions, and nanoliposomes) can enhance the bioavailability and therapeutic efficacy of gingerols by preserving their inherent properties and addressing challenges of stability, solubility, and absorption. CONCLUSION: Gingerols are promising therapeutic agents to modulate gut microbiome (increase beneficial bacteria and inhibit pathogenic microbes), and attenuate chronic disease symptoms such as diabetes, colitis, obesity, oxidative stress, and cancer. Despite significant progress, challenges persist in transforming research findings into industrial applications, such as stability and solubility during processing and low bioavailability in the distal gut to impart desirable health benefits.},
	doi = {10.1016/j.phymed.2024.156352},
	pmid = {39740381 [Indexed for MEDLINE]}
}

