@ARTICLE{10.1002/advs.202206957,
	author = {Yu J and Guo Z and Yan J and Bu C and Peng C and Li C and Mao R and Zhang J and Wang Z and Chen S and Yao M and Xie Z and Yang C and Yang YY and Yuan P and Ding X},
	title = {Gastric Acid-Responsive ROS Nanogenerators for Effective Treatment of Helicobacter pylori Infection without Disrupting Homeostasis of Intestinal Flora.},
	journal = {Adv Sci (Weinh)},
	year = {2023},
	abstract = {Helicobacter pylori (H. pylori) has infected more than half of the world's population, and is the major cause of gastric cancer. The efficacy of standard antibiotic-based triple therapy is declining due to drug resistance development. Herein, a pH-responsive reactive oxygen species (ROS) nanogenerator (Fe-HMME@DHA@MPN) composed of acid-responsive metal polyphenol network (MPN) shell and mesoporous metal-organic nanostructure core [Fe-HMME (hematoporphyrin monomethyl ether, sonosensitizer)] loaded with dihydroartemisinin (DHA) is reported. These nanoparticles generate more ROS singlet oxygen than sonosensitizer HMME under ultrasonication, and this sonodynamic process is fueled by oxygen generated through Fenton/Fenton-like reactions of the degraded product in gastric acid Fe (II) and hydrogen peroxide (H2 O2 ) in the infection microenvironment. The encapsulated DHA, as a hydroperoxide source, is found to enhance the peroxidase-like activity of the Fe-HMME@DHA@MPN to generate ROS hydroxyl radical, beneficial for the microenvironment without sufficient H2 O2 . In vitro experiments demonstrate that the ROS nanogenerators are capable of killing multidrug-resistant H. pylori and removing biofilm, and ROS nanogenerators show high therapeutic efficacy in a H. pylori infection mouse model. Unlike the triple therapy, the nanogenerators display negligible side effects toward the normal gut microbiota. Taken together, these self-enhanced ROS nanogenerators have a great potential for treatment of H. pylori infection.},
	doi = {10.1002/advs.202206957},
	pmid = {37127895 [Indexed for MEDLINE]},
	note = {PMC10369278}
}

@ARTICLE{10.1007/s00204-022-03391-2,
	author = {Vivarelli S and Costa C and Teodoro M, Giambò F and Tsatsakis AM and Fenga C},
	title = {Polyphenols: a route from bioavailability to bioactivity addressing potential health benefits to tackle human chronic diseases.},
	journal = {Arch Toxicol},
	year = {2023},
	abstract = {Chronic pathologies or non-communicable diseases (NCDs) include cardiovascular diseases, metabolic syndrome, neurological diseases, respiratory disorders and cancer. They are the leading global cause of human mortality and morbidity. Given their chronic nature, NCDs represent a growing social and economic burden, hence urging the need for ameliorating the existing preventive strategies, and for finding novel tackling therapies. NCDs are highly correlated with unhealthy lifestyle habits (such as high-fat and high-glucose diet, or sedentary life). In general, lifestyle approaches that might improve these habits, including dietary consumption of fresh vegetables, fruits and fibers, may contrast NCD symptoms and prolong life expectancy of affected people. Polyphenols (PPLs) are plant-derived molecules with demonstrated biological activities in humans, which include: radical scavenging and anti-oxidant activities, capability to modulate inflammation, as well as human enzymes, and even to bind nuclear receptors. For these reasons, PPLs are currently tested, both preclinically and clinically, as dietary adjuvants for the prevention and treatment of NCDs. In this review, we describe the human metabolism and bioactivity of PPLs. Also, we report what is currently known about PPLs interaction with gastro-intestinal enzymes and gut microbiota, which allows their biotransformation in many different metabolites with several biological functions. The systemic bioactivity of PPLs and the newly available PPL-delivery nanosystems are also described in detail. Finally, the up-to-date clinical studies assessing both safety and efficacy of dietary PPLs in individuals with different NCDs are hereby reported. Overall, the clinical results support the notion that PPLs from fruits, vegetables, but also from leaves or seeds extracts, are safe and show significant positive results in ameliorating symptoms and improving the whole quality of life of people with NCDs.},
	doi = {10.1007/s00204-022-03391-2},
	pmid = {36260104 [Indexed for MEDLINE]}
}

@ARTICLE{10.3390/antiox11081481,
	author = {Yang ZJ and Huang SY and Zhou DD and Xiong RG and Zhao CN and Fang AP and Zhang YJ and Li HB and Zhu HL},
	title = {Effects and Mechanisms of Curcumin for the Prevention and Management of Cancers: An Updated Review.},
	journal = {Antioxidants (Basel)},
	year = {2022},
	abstract = {Cancer is the leading cause of death in the world. Curcumin is the main ingredient in turmeric (Curcuma longa L.), and is widely used in the food industry. It shows anticancer properties on different types of cancers, and the underlying mechanisms of action include inhibiting cell proliferation, suppressing invasion and migration, promoting cell apoptosis, inducing autophagy, decreasing cancer stemness, increasing reactive oxygen species production, reducing inflammation, triggering ferroptosis, regulating gut microbiota, and adjuvant therapy. In addition, the anticancer action of curcumin is demonstrated in clinical trials. Moreover, the poor water solubility and low bioavailability of curcumin can be improved by a variety of nanotechnologies, which will promote its clinical effects. Furthermore, although curcumin shows some adverse effects, such as diarrhea and nausea, it is generally safe and tolerable. This paper is an updated review of the prevention and management of cancers by curcumin with a special attention to its mechanisms of action.},
	doi = {10.3390/antiox11081481},
	pmid = {36009200},
	note = {PMC9405286}
}

@ARTICLE{10.1016/j.apsb.2021.08.016,
	author = {Chen Q and Li Q and Liang Y and Zu M and Chen N and Canup BSB and Luo L and Wang C and Zeng L and Xiao B},
	title = {Natural exosome-like nanovesicles from edible tea flowers suppress metastatic breast cancer via ROS generation and microbiota modulation.},
	journal = {Acta Pharm Sin B},
	year = {2022},
	abstract = {Although several artificial nanotherapeutics have been approved for practical treatment of metastatic breast cancer, their inefficient therapeutic outcomes, serious adverse effects, and high cost of mass production remain crucial challenges. Herein, we developed an alternative strategy to specifically trigger apoptosis of breast tumors and inhibit their lung metastasis by using natural nanovehicles from tea flowers (TFENs). These nanovehicles had desirable particle sizes (131 nm), exosome-like morphology, and negative zeta potentials. Furthermore, TFENs were found to contain large amounts of polyphenols, flavonoids, functional proteins, and lipids. Cell experiments revealed that TFENs showed strong cytotoxicities against cancer cells due to the stimulation of reactive oxygen species (ROS) amplification. The increased intracellular ROS amounts could not only trigger mitochondrial damage, but also arrest cell cycle, resulting in the in vitro anti-proliferation, anti-migration, and anti-invasion activities against breast cancer cells. Further mice investigations demonstrated that TFENs after intravenous (i.v.) injection or oral administration could accumulate in breast tumors and lung metastatic sites, inhibit the growth and metastasis of breast cancer, and modulate gut microbiota. This study brings new insights to the green production of natural exosome-like nanoplatform for the inhibition of breast cancer and its lung metastasis via i.v. and oral routes.},
	doi = {10.1016/j.apsb.2021.08.016},
	pmid = {35256954},
	note = {PMC8897038}
}

@ARTICLE{10.1186/s43088-022-00196-1,
	author = {Tripathi AK and Ray AK and Mishra SK},
	title = {Molecular and pharmacological aspects of piperine as a potential molecule for disease prevention and management: evidence from clinical trials.},
	journal = {Beni Suef Univ J Basic Appl Sci},
	year = {2022},
	abstract = {BACKGROUND: Piperine is a type of amide alkaloid that exhibits pleiotropic properties like antioxidant, anticancer, anti-inflammatory, antihypertensive, hepatoprotective, neuroprotective and enhancing bioavailability and fertility-related activities. Piperine has the ability to alter gastrointestinal disorders, drug-metabolizing enzymes, and bioavailability of several drugs. The present review explores the available clinical and preclinical data, nanoformulations, extraction process, structure-activity relationships, molecular docking, bioavailability enhancement of phytochemicals and drugs, and brain penetration properties of piperine in the prevention, management, and treatment of various diseases and disorders. MAIN BODY: Piperine provides therapeutic benefits in patients suffering from diabetes, obesity, arthritis, oral cancer, breast cancer, multiple myeloma, metabolic syndrome, hypertension, Parkinson's disease, Alzheimer's disease, cerebral stroke, cardiovascular diseases, kidney diseases, inflammatory diseases, and rhinopharyngitis. The molecular basis for the pleiotropic activities of piperine is based on its ability to regulate multiple signaling molecules such as cell cycle proteins, anti-apoptotic proteins, P-glycoprotein, cytochrome P450 3A4, multidrug resistance protein 1, breast cancer resistance protein, transient receptor potential vanilloid 1 proinflammatory cytokine, nuclear factor-κB, c-Fos, cAMP response element-binding protein, activation transcription factor-2, peroxisome proliferator-activated receptor-gamma, Human G-quadruplex DNA, Cyclooxygenase-2, Nitric oxide synthases-2, MicroRNA, and coronaviruses. Piperine also regulates multiple signaling pathways such as Akt/mTOR/MMP-9, 5'-AMP-activated protein kinase-activated NLR family pyrin domain containing-3 inflammasome, voltage-gated K+ current, PKCα/ERK1/2, NF-κB/AP-1/MMP-9, Wnt/β-catenin, JNK/P38 MAPK, and gut microbiota. SHORT CONCLUSION: Based on the current evidence, piperine can be the potential molecule for treatment of disease, and its significance of this molecule in the clinic is discussed.},
	doi = {10.1186/s43088-022-00196-1},
	pmid = {35127957},
	note = {PMC8796742}
}

@ARTICLE{10.1016/j.biopha.2022.112654,
	author = {Du Y and Wan H and Huang P and Yang J and He Y},
	title = {A critical review of Astragalus polysaccharides: From therapeutic mechanisms to pharmaceutics.},
	journal = {Biomed Pharmacother},
	year = {2022},
	abstract = {As the important active ingredients of Astragali Radix (AR), Astragalus polysaccharides (APs) have therapeutic potential for multiple diseases including nervous system diseases, cardiovascular diseases, diabetes mellitus, and cancer. A large number of cell experiments combined with animal experiments have shed light on the therapeutic mechanisms and therapeutic effects of APs on a variety of diseases. However, the clinical application of APs is not widespread, except for the use of injected APs in the clinical adjuvant therapy of cancer. Due to the excessive molecular weight, bulky, low solubility and negatively charged characteristics, APs have low bioavailability which limits their clinical application. With the deepening of researches on the pharmaceutics of APs, the nanocrystals and moderate structural modification enormously boost the bioavailability, which may expand the application of APs. This review summarizes the studies in pharmacodynamic properties and pharmaceutics of APs, with the purpose of providing experimental researches and clinical application data for expanding the clinical development through expounding the therapeutic mechanisms and pharmaceutical researches of APs.},
	doi = {10.1016/j.biopha.2022.112654},
	pmid = {35086031 [Indexed for MEDLINE]}
}

@ARTICLE{10.3389/fphar.2021.797634,
	author = {Li M and Wang X and Wang Y and Bao S and Chang Q and Liu L and Zhang S and Sun L},
	title = {Strategies for Remodeling the Tumor Microenvironment Using Active Ingredients of Ginseng-A Promising Approach for Cancer Therapy.},
	journal = {Front Pharmacol},
	year = {2021},
	abstract = {The tumor microenvironment (TME) plays a key role in promoting the initiation and progression of tumors, leading to chemoradiotherapy resistance and immunotherapy failure. Targeting of the TME is a novel anti-tumor therapeutic approach and is currently a focus of anti-tumor research. Panax ginseng C. A. Meyer (ginseng), an ingredient of well-known traditional Asia medicines, exerts beneficial anti-tumor effects and can regulate the TME. Here, we present a systematic review that describes the current status of research efforts to elucidate the functions and mechanisms of ginseng active components (including ginsenosides and ginseng polysaccharides) for achieving TME regulation. Ginsenosides have variety effects on TME, such as Rg3, Rd and Rk3 can inhibit tumor angiogenesis; Rg3, Rh2 and M4 can regulate the function of immune cells; Rg3, Rd and Rg5 can restrain the stemness of cancer stem cells. Ginseng polysaccharides (such as red ginseng acidic polysaccharides and polysaccharides extracted from ginseng berry and ginseng leaves) can regulate TME mainly by stimulating immune cells. In addition, we propose a potential mechanistic link between ginseng-associated restoration of gut microbiota and the tumor immune microenvironment. Finally, we describe recent advances for improving ginseng efficacy, including the development of a nano-drug delivery system. Taken together, this review provides novel perspectives on potential applications for ginseng active ingredients as anti-cancer adjuvants that achieve anti-cancer effects by reshaping the tumor microenvironment.},
	doi = {10.3389/fphar.2021.797634},
	pmid = {35002732},
	note = {PMC8727883}
}

@ARTICLE{10.1016/j.addr.2021.114021,
	author = {Lee Y and Kamada N and Moon JJ},
	title = {Oral nanomedicine for modulating immunity, intestinal barrier functions, and gut microbiome.},
	journal = {Adv Drug Deliv Rev},
	year = {2021},
	abstract = {The gastrointestinal tract (GIT) affects not only local diseases in the GIT but also various systemic diseases. Factors that can affect the health and disease of both GIT and the human body include 1) the mucosal immune system composed of the gut-associated lymphoid tissues and the lamina propria, 2) the intestinal barrier composed of mucus and intestinal epithelium, and 3) the gut microbiota. Selective delivery of drugs, including antigens, immune-modulators, intestinal barrier enhancers, and gut-microbiome manipulators, has shown promising results for oral vaccines, immune tolerance, treatment of inflammatory bowel diseases, and other systemic diseases, including cancer. However, physicochemical and biological barriers of the GIT present significant challenges for successful translation. With the advances of novel nanomaterials, oral nanomedicine has emerged as an attractive option to not only overcome these barriers but also to selectively deliver drugs to the target sites in GIT. In this review, we discuss the GIT factors and physicochemical and biological barriers in the GIT. Furthermore, we present the recent progress of oral nanomedicine for oral vaccines, immune tolerance, and anti-inflammation therapies. We also discuss recent advances in oral nanomedicine designed to fortify the intestinal barrier functions and modulate the gut microbiota and microbial metabolites. Finally, we opine about the future directions of oral nano-immunotherapy.},
	doi = {10.1016/j.addr.2021.114021},
	pmid = {34710529 [Indexed for MEDLINE]},
	note = {PMC8665886}
}

@ARTICLE{10.1016/j.biomaterials.2021.121178,
	author = {Zu M and Xie D and Canup BSB and Chen N and Wang Y and Sun R and Zhang Z and Fu Y and Dai F and Xiao B},
	title = {'Green' nanotherapeutics from tea leaves for orally targeted prevention and alleviation of colon diseases.},
	journal = {Biomaterials},
	year = {2021},
	abstract = {Although synthesized nanotherapeutics (NTs) are attractive for the oral treatment of colon diseases, their clinical translations are constrained by the unsatisfactory therapeutic outcomes, potential adverse effects, and high cost of mass production. Here, we report the development of tea leaf-derived natural NTs with desirable particle sizes (140.0 nm) and negative surface charge (-14.6 mV). These natural exosome-like NTs were found to contain large amounts of lipids, some functional proteins, and many bioactive small molecules. Specifically, galactose groups on the surface of NTs could mediate their specific internalization by macrophages via galactose receptor-mediated endocytosis. Moreover, these NTs were able to reduce the production of reactive oxygen species, inhibit the expression of pro-inflammatory cytokines, and increase the amount of anti-inflammatory IL-10 secreted by macrophages. Orally administered NTs could efficiently inhibit the inflammatory bowel responses, restore disrupted colonic barriers and enhance the diversity and overall abundance of gut microbiota, thereby preventing or alleviating inflammatory bowel disease and colitis-associated colon cancer. The present study brings new insights to the facile application of a versatile and robust natural nanoplatform for the prevention and treatment of colon diseases.},
	doi = {10.1016/j.biomaterials.2021.121178},
	pmid = {34656857 [Indexed for MEDLINE]}
}

@ARTICLE{10.3389/fphar.2021.650141,
	author = {Chen H and Li R and Zhang F and Yao Q and Guo Y},
	title = {A Scientometric Visualization Analysis for Natural Products on Cancer Research from 2008 to 2020.},
	journal = {Front Pharmacol},
	year = {2021},
	abstract = {Background: An increasing number of studies have shown that natural products have anti-tumor effects, and it has become a hotspot in cancer research. However, few bibliometric analyses have been examined in this field systematically. The current study aimed to explore the status and provide the developing trends in the natural products on cancer research. Methods: Publications on natural products in cancer research were extracted from the Web of Science core collection database. CiteSpace (5.6.R3) software and GraphPad prism 6 were used to analyze and plot the references. Results: On February 1, 2021, 34,611 records of natural products in cancer research published from 2008 to 2020 were collected. The United States was the driving force, with a strong academic reputation in this area. The top-contributing institution was the Chinese Academy of Sciences. Most publications were published in Molecules. Efferth Thomas was the most prolific author, while Newman DJ was the most cited and frequently co-cited author. Flavonoid, curcumin, and polyphenol were the most widely studied natural products. Oleanolic acid and rosmarinic acid have gradually become research hotspots recently. Breast cancer, prostate cancer, and colorectal cancer were the most common types of cancer in this field. "Natural killer cell" was the leading research hotspot. The keywords of "leaf extract," "molecular docking" and "gold nanoparticle" appeared most recently as research frontiers. Conclusion: Our results provided a general overview of the major research directions of natural products research in cancer. The mechanisms of natural products, especially those related to molecular docking, gold nanoparticle, gut microbiota, and immune checkpoints may soon become hotspots and should be closely monitored.},
	doi = {10.3389/fphar.2021.650141},
	pmid = {34421584},
	note = {PMC8377543}
}

@ARTICLE{10.1016/j.foodres.2021.110522,
	author = {Ouyang Y and Qiu Y and Liu Y and Zhu R and Chen Y and El-Seedi HR and Chen X and Zhao C},
	title = {Cancer-fighting potentials of algal polysaccharides as nutraceuticals.},
	journal = {Food Res Int},
	year = {2021},
	abstract = {Cancer has been listed as one of the world's five incurable diseases by the World Health Organization and causes tens of thousands of deaths every year. Unfortunately, anticancer agents either show limited efficacy or show serious side effects. The algae possess high nutritional value and their polysaccharides have a variety of biological activities, especially anti-cancer and immunomodulatory properties. Algal polysaccharides exert anti-cancer effects by inducing apoptosis, cell cycle arrest, anti-angiogenesis, and regulating intestinal flora and immune function. Algal polysaccharides can be combined with nanoparticles and other drugs to reduce the side effects caused by chemotherapy and increase the anticancer effects. This review shows the signal pathways related to the anti-cancer mechanisms of algal polysaccharides, including their influence on intestinal flora and immune regulation, the application of nanoparticles, and the effects on combination therapy and clinical trials of cancer treatments.},
	doi = {10.1016/j.foodres.2021.110522},
	pmid = {34399500 [Indexed for MEDLINE]}
}

@ARTICLE{10.1021/acsomega.1c02162,
	author = {Suresh AP and Kalarikkal SP and Pullareddy B and Sundaram GM},
	title = {Low pH-Based Method to Increase the Yield of Plant-Derived Nanoparticles from Fresh Ginger Rhizomes.},
	journal = {ACS Omega},
	year = {2021},
	abstract = {Plant-derived nanoparticles (PDNPs) are naturally occurring exosome-like nanovesicles derived from dietary plants containing key plant bioactives. Ginger-derived PDNPs have a therapeutic effect on alcohol-induced liver injury, inflammatory bowel disease, and colon cancer. PDNPs are conventionally purified by differential ultracentrifugation, a technique not amenable for scale up. We have recently developed a polyethylene glycol (PEG) 6000-based method for cost-effective purification of ginger PDNPs, with comparable efficiency to differential ultracentrifugation (Sci. Rep. 2020, 10 (1), 4456.). Herein, we report a 4-5-fold higher ginger PDNP recovery when PEG precipitation was carried out in low pH conditions (pH 4 and 5). Low pH-derived ginger PDNPs were smaller in size without an overt change in zeta potential. The spontaneous intracellular entry and protection against oxidative stress in A431 cells were similar between ginger PDNPs purified under low, neutral, and alkaline pH. Low-pH purified ginger PDNPs had higher levels of total polyphenolic content compared to PDNPs purified under neutral and alkaline pH. Recently, ginger PDNP-derived microRNAs have been shown to exhibit cross-kingdom regulation by targeting human, gut microbiome, and viral transcripts. Using qRT-PCR, we also verified the presence of miRNAs that were predicted to target SARS-CoV-2 in ginger PDNPs purified under low pH. Thus, we have developed a method to purify ginger PDNPs in high yields by using low-pH conditions without affecting the major bioactive contents of PDNPs.},
	doi = {10.1021/acsomega.1c02162},
	pmid = {34278148},
	note = {PMC8280662}
}

@ARTICLE{10.3390/molecules26113301,
	author = {Jiang Y and Jiang Z and Ma L and Huang Q},
	title = {Advances in Nanodelivery of Green Tea Catechins to Enhance the Anticancer Activity.},
	journal = {Molecules},
	year = {2021},
	abstract = {Cancer is one of the leading causes of death globally. A variety of phenolic compounds display preventative and therapeutic effects against cancers. Green teas are rich in phenolics. Catechins are the most dominant phenolic component in green teas. Studies have shown that catechins have anticancer activity in various cancer models. The anticancer activity of catechins, however, may be compromised due to their low oral bioavailability. Nanodelivery emerges as a promising way to improve the oral bioavailability and anticancer activity of catechins. Research in this area has been actively conducted in recent decades. This review provides the molecular mechanisms of the anticancer effects of catechins, the factors that limit the oral bioavailability of catechins, and the latest advances of delivering catechins using nanodelivery systems through different routes to enhance their anticancer activity.},
	doi = {10.3390/molecules26113301},
	pmid = {34072700 [Indexed for MEDLINE]},
	note = {PMC8198522}
}

@ARTICLE{10.1016/j.jnutbio.2021.108623,
	author = {Vazhappilly CG and Amararathna M and Cyril AC and Linger R and Matar R and Merheb M and Ramadan WS and Radhakrishnan R and Rupasinghe HPV},
	title = {Current methodologies to refine bioavailability, delivery, and therapeutic efficacy of plant flavonoids in cancer treatment.},
	journal = {J Nutr Biochem},
	year = {2021},
	abstract = {Over the last two decades, several advancements have been made to improve the therapeutic efficacy of plant flavonoids, especially in cancer treatment. Factors such as low bioavailability, poor flavonoid stability and solubility, ineffective targeted delivery, and chemo-resistance hinder the application of flavonoids in anti-cancer therapy. Many anti-cancer compounds failed in the clinical trials because of unexpected altered clearance of flavonoids, poor absorption after administration, low efficacy, and/or adverse effects. Hence, the current research strategies are focused on improving the therapeutic efficacy of plant flavonoids, especially by enhancing their bioavailability through combination therapy, engineering gut microbiota, regulating flavonoids interaction with adenosine triphosphate binding cassette efflux transporters, and efficient delivery using nanocrystal and encapsulation technologies. This review aims to discuss different methodologies with examples from reported dietary flavonoids that showed an enhanced anti-cancer efficacy in both in vitro and in vivo models. Further, the review discusses the recent progress in biochemical modifications of flavonoids to improve bioavailability, solubility, and therapeutic efficacy.},
	doi = {10.1016/j.jnutbio.2021.108623},
	pmid = {33705948 [Indexed for MEDLINE]}
}

@ARTICLE{10.3389/fimmu.2020.615240,
	author = {Cuzzubbo S and Mangsbo S and Nagarajan D and Habra K and Pockley AG and McArdle SEB},
	title = {Cancer Vaccines: Adjuvant Potency, Importance of Age, Lifestyle, and Treatments.},
	journal = {Front Immunol},
	year = {2021},
	abstract = {Although the discovery and characterization of multiple tumor antigens have sparked the development of many antigen/derived cancer vaccines, many are poorly immunogenic and thus, lack clinical efficacy. Adjuvants are therefore incorporated into vaccine formulations to trigger strong and long-lasting immune responses. Adjuvants have generally been classified into two categories: those that 'depot' antigens (e.g. mineral salts such as aluminum hydroxide, emulsions, liposomes) and those that act as immunostimulants (Toll Like Receptor agonists, saponins, cytokines). In addition, several novel technologies using vector-based delivery of antigens have been used. Unfortunately, the immune system declines with age, a phenomenon known as immunosenescence, and this is characterized by functional changes in both innate and adaptive cellular immunity systems as well as in lymph node architecture. While many of the immune functions decline over time, others paradoxically increase. Indeed, aging is known to be associated with a low level of chronic inflammation-inflamm-aging. Given that the median age of cancer diagnosis is 66 years and that immunotherapeutic interventions such as cancer vaccines are currently given in combination with or after other forms of treatments which themselves have immune-modulating potential such as surgery, chemotherapy and radiotherapy, the choice of adjuvants requires careful consideration in order to achieve the maximum immune response in a compromised environment. In addition, more clinical trials need to be performed to carefully assess how less conventional form of immune adjuvants, such as exercise, diet and psychological care which have all be shown to influence immune responses can be incorporated to improve the efficacy of cancer vaccines. In this review, adjuvants will be discussed with respect to the above-mentioned important elements.},
	doi = {10.3389/fimmu.2020.615240},
	pmid = {33679703 [Indexed for MEDLINE]},
	note = {PMC7927599}
}

@ARTICLE{10.1016/j.ejpb.2020.12.004,
	author = {Dos Santos AM and Meneguin AB and Akhter DT and Fletcher N and Houston ZH and Bell C and Thurecht KJ, Gremião MPD},
	title = {Understanding the role of colon-specific microparticles based on retrograded starch/pectin in the delivery of chitosan nanoparticles along the gastrointestinal tract.},
	journal = {Eur J Pharm Biopharm},
	year = {2021},
	abstract = {The encapsulation of nanoparticles within microparticles designed for specific delivery to the colon is a relevant strategy to avoid premature degradation or release of nanoparticles during their passage through the stomach and upper gastrointestinal tract (GIT), allowing the targeted delivery of chemotherapeutics to the colon after oral administration. Here, we designed an oral multiparticulate system to achieve targeted release in the colon. In this sense, chitosan nanoparticles (CS NPs) encapsulated with 5-fluorouracil (5-FU) and incorporated into retrograded starch and pectin (RS/P) microparticles were developed and their in vivo distribution along the mouse GIT after oral administration was monitored using multispectral optical imaging. In vitro release studies revealed that the encapsulation of CS NPs into RS/P microparticles promoted greater control of 5-FU release rates, with a significant reduction (53%) in acid media that might replicate that found in the stomach following oral administration. The evaluation of the in vivo biodistribution of the CS NPs in mice showed a faster clearance in the distribution pattern along the mouse GIT, i.e., a shorter transit time of CS NPs compared to CS NPs-loaded RS/P microparticles. Additionally, CS NPs alone showed non-specific absorption into the blood-stream with associated kidney accumulation, while for the CS NPs-loaded RS/P microparticles no significant accumulation was observed in blood or major clearance organs. This suggests the specific degradability of RS/P by the colon microbiota appears to have been decisive in the higher protection of the CS NPs along the GIT until release in the colon, preventing unwanted absorption into the bloodstream and major organs following oral administration. Our findings represent a proof of concept for the use of RS/P microparticles as potential carriers for delivering drug-loaded nanoparticles to the colon and this work will contribute to the development of oral-systems for colorectal cancer therapy.},
	doi = {10.1016/j.ejpb.2020.12.004},
	pmid = {33309846 [Indexed for MEDLINE]}
}

@ARTICLE{10.1080/10408398.2020.1829541,
	author = {Farha AK and Gan RY and Li HB and Wu DT and Atanasov AG and Gul K and Zhang JR and Yang QQ and Corke H},
	title = {The anticancer potential of the dietary polyphenol rutin: Current status, challenges, and perspectives.},
	journal = {Crit Rev Food Sci Nutr},
	year = {2022},
	abstract = {Rutin is one of the most common dietary polyphenols found in vegetables, fruits, and other plants. It is metabolized by the mammalian gut microbiota and absorbed from the intestines, and becomes bioavailable in the form of conjugated metabolites. Rutin exhibits a plethora of bioactive properties, making it an extremely promising phytochemical. Numerous studies demonstrate that rutin can act as a chemotherapeutic and chemopreventive agent, and its anticancer effects can be mediated through the suppression of cell proliferation, the induction of apoptosis or autophagy, and the hindering of angiogenesis and metastasis. Rutin has been found to modulate multiple molecular targets involved in carcinogenesis, such as cell cycle mediators, cellular kinases, inflammatory cytokines, transcription factors, drug transporters, and reactive oxygen species. This review summarizes the natural sources of rutin, its bioavailability, and in particular its potential use as an anticancer agent, with highlighting its anticancer mechanisms as well as molecular targets. Additionally, this review updates the anticancer potential of its analogs, nanoformulations, and metabolites, and discusses relevant safety issues. Overall, rutin is a promising natural dietary compound with promising anticancer potential and can be widely used in functional foods, dietary supplements, and pharmaceuticals for the prevention and management of cancer.},
	doi = {10.1080/10408398.2020.1829541},
	pmid = {33054344 [Indexed for MEDLINE]}
}

@ARTICLE{10.1016/j.ijbiomac.2020.09.214,
	author = {Shah BM and Palakurthi SS and Khare T and Khare S and Palakurthi S},
	title = {Natural proteins and polysaccharides in the development of micro/nano delivery systems for the treatment of inflammatory bowel disease.},
	journal = {Int J Biol Macromol},
	year = {2020},
	abstract = {Treatments for inflammatory bowel disease (IBD) are typically immunosuppressive. Despite a range of treatment options, limited efficacy, systemic toxicities like bone marrow suppression, infections and malignancy are their serious setbacks. There exists an unmet medical need for novel therapeutic agents without safety concerns resulting from chronic, systemic immunosuppression. Of late, several natural agents with better therapeutic potential have been reported. It is very likely that restricting the release of the active molecules to the intestine would further improve their clinical efficacy and safety. To this end, novel polymer-based micro/nano formulations protect the drug from gastric environment and slowly release the drug in the colon. However, cost and side-effects associated to synthetic polymers have led to the development of biocompatible, economic and pharmaceutically well-accepted biomacromolecules in exploring their potential in IBD. Since last few years, biological proteins, polysaccharides and their combinations have shown great efficacy in colitis induced animal models. In this review, micro/nano formulations developed using biomacromolecules like chitosan, zein, pectin, casein, alginate, dextran, glucomannan and hyaluronic acid have been reviewed focusing on their potential in protecting active cargo, avoiding premature release, distal colon targeting along with their impact on reshaping the altered gut microbiota and how it can ameliorate the colitis conditions.},
	doi = {10.1016/j.ijbiomac.2020.09.214},
	pmid = {33010274 [Indexed for MEDLINE]}
}

@ARTICLE{10.2174/1567201817666200527133719,
	author = {Chadha S and Kumar A and Srivastava SA and Behl T and Ranjan R},
	title = {Inulin as a Delivery Vehicle for Targeting Colon-Specific Cancer.},
	journal = {Curr Drug Deliv},
	year = {2020},
	abstract = {Natural polysaccharides, as well as biopolymers, are now days widely developed for targeting colon cancer using various drug delivery systems. Currently, healing conformations are being explored that can efficiently play a multipurpose role. Owing to the capability of extravagance colonic diseases with the least adverse effects, biopolymers for site specific colon delivery have developed an increased curiosity over the past decades. Inulin (INU) was explored for its probable application as an entrapment material concerning its degradation by enzymes in the colonic microflora and its drug release behavior in a sustained and controlled manner. INU is a polysaccharide and it consists of 2 to 1 linkage having an extensive array of beneficial uses such as a carrier for delivery of therapeutic agents as an indicative/investigative utensil or as a dietary fiber with added well-being aids. In the main, limited research, as well as information, is available on the delivery of therapeutic agents using inulin specifically for colon cancer because of its capability to subsist in the stomach's acidic medium. This exceptional steadiness and robustness properties are exploited in numerous patterns to target drugs securely for the management of colonic cancer, where they effectively act and kills colonic tumor cells easily. In this review article, recent efforts and inulin-based nano-technological approaches for colon cancer targeting are presented and discussed.},
	doi = {10.2174/1567201817666200527133719},
	pmid = {32459607 [Indexed for MEDLINE]}
}

@ARTICLE{10.3390/microorganisms8020199,
	author = {Reddy VP and Aryal P and Robinson S and Rafiu R and Obrenovich M and Perry G},
	title = {Polyphenols in Alzheimer's Disease and in the Gut-Brain Axis.},
	journal = {Microorganisms},
	year = {2020},
	abstract = {Polyphenolic antioxidants, including dietary plant lignans, modulate the gut-brain axis, which involves transformation of these polyphenolic compounds into physiologically active and neuroprotector compounds (called human lignans) through gut bacterial metabolism. These gut bacterial metabolites exert their neuroprotective effects in various neurodegenerative diseases, such as Alzheimer's disease (AD) and Parkinson's disease (PD), and also have protective effects against other diseases, such as cardiovascular diseases, cancer, and diabetes. For example, enterolactone and enterodiol, the therapeutically relevant polyphenols, are formed as the secondary gut bacterial metabolites of lignans, the non-flavonoid polyphenolic compounds found in plant-based foods. These compounds are also acetylcholinesterase inhibitors, and thereby have potential applications as therapeutics in AD and other neurological diseases. Polyphenols are also advanced glycation end product (AGE) inhibitors (antiglycating agents), and thereby exert neuroprotective effects in cases of AD. Thus, gut bacterial metabolism of lignans and other dietary polyphenolic compounds results in the formation of neuroprotective polyphenols-some of which have enhanced blood-brain barrier permeability. It is hypothesized that gut bacterial metabolism-derived polyphenols, when combined with the nanoparticle-based blood-brain barrier (BBB)-targeted drug delivery, may prove to be effective therapeutics for various neurological disorders, including traumatic brain injury (TBI), AD, and PD. This mini-review addresses the role of polyphenolic compounds in the gut-brain axis, focusing on AD.},
	doi = {10.3390/microorganisms8020199},
	pmid = {32023969},
	note = {PMC7074796}
}

@ARTICLE{10.3390/nu11051026,
	author = {Chen J and Zhao KN and Vitetta L},
	title = {Effects of Intestinal Microbial−Elaborated Butyrate on Oncogenic Signaling Pathways.},
	journal = {Nutrients},
	year = {2019},
	abstract = {The intestinal microbiota is well known to have multiple benefits on human health, including cancer prevention and treatment. The effects are partially mediated by microbiota-produced short chain fatty acids (SCFAs) such as butyrate, propionate and acetate. The anti-cancer effect of butyrate has been demonstrated in cancer cell cultures and animal models of cancer. Butyrate, as a signaling molecule, has effects on multiple signaling pathways. The most studied effect is its inhibition on histone deacetylase (HDAC), which leads to alterations of several important oncogenic signaling pathways such as JAK2/STAT3, VEGF. Butyrate can interfere with both mitochondrial apoptotic and extrinsic apoptotic pathways. In addition, butyrate also reduces gut inflammation by promoting T-regulatory cell differentiation with decreased activities of the NF-κB and STAT3 pathways. Through PKC and Wnt pathways, butyrate increases cancer cell differentiation. Furthermore, butyrate regulates oncogenic signaling molecules through microRNAs and methylation. Therefore, butyrate has the potential to be incorporated into cancer prevention and treatment regimens. In this review we summarize recent progress in butyrate research and discuss the future development of butyrate as an anti-cancer agent with emphasis on its effects on oncogenic signaling pathways. The low bioavailability of butyrate is a problem, which precludes clinical application. The disadvantage of butyrate for medicinal applications may be overcome by several approaches including nano-delivery, analogue development and combination use with other anti-cancer agents or phytochemicals.},
	doi = {10.3390/nu11051026},
	pmid = {31067776 [Indexed for MEDLINE]},
	note = {PMC6566851}
}

@ARTICLE{10.1039/c8fo02295j,
	author = {Rome S},
	title = {Biological properties of plant-derived extracellular vesicles.},
	journal = {Food Funct},
	year = {2019},
	abstract = {Identification of active constituents of our diet is crucial to understand the impact of food on health, and disease development, and for the formulation of functional food and nutraceuticals. Until now research into the pharmacological properties of the components of our diet has focused on vitamins, sterols, polyphenols, fiber, etc. But very recently, it has been found that plants contain various types of vesicles which are in contact with the intestinal tract throughout our lives. They participate in intestinal tissue renewal processes and modulate gut microbiota in healthy subjects and have important biological functions against inflammatory diseases (e.g.; colitis injury, liver steatosis) or cancers associated with their specific lipid and miRNA content. In addition, recent data have suggested that plant-derived nanovesicles would be excellent candidates for the delivery of therapeutic agents (e.g.; anti-cancerous drugs, siRNAs) or poorly soluble natural compounds (e.g.; curcumin), as they are able to cross mammalian barriers without inducing either an inflammatory response or necrosis, conversely to conventional liposomes. It is thus important to consider these plant-derived vesicles as new components of our food in order to evaluate their potential for health benefit and food-derived technology.},
	doi = {10.1039/c8fo02295j},
	pmid = {30724295 [Indexed for MEDLINE]}
}

@ARTICLE{10.1080/10408398.2016.1231168,
	author = {Gan RY and Li HB and Sui ZQ and Corke H},
	title = {Absorption, metabolism, anti-cancer effect and molecular targets of epigallocatechin gallate (EGCG): An updated review.},
	journal = {Crit Rev Food Sci Nutr},
	year = {2018},
	abstract = {Green tea is one of the most popular beverages in the world, especially in Asian countries. Consumption of green tea has been demonstrated to possess many health benefits, which mainly attributed to the main bioactive compound epigallocatechin gallate (EGCG), a flavone-3-ol polyphenol, in green tea. EGCG is mainly absorbed in the intestine, and gut microbiota play a critical role in its metabolism prior to absorption. EGCG exhibits versatile bioactivities, with its anti-cancer effect most attracting due to the cancer preventive effect of green tea consumption, and a great number of studies intensively investigated its anti-cancer effect. In this review, we therefore, first stated the absorption and metabolism process of EGCG, and then summarized its anti-cancer effect in vitro and in vivo, including its manifold anti-cancer actions and mechanisms, especially its anti-cancer stem cell effect, and next highlighted its various molecular targets involved in cancer inhibition. Finally, the anti-cancer effect of EGCG analogs and nanoparticles, as well as the potential cancer promoting effect of EGCG were also discussed. Understanding of the absorption, metabolism, anti-cancer effect and molecular targets of EGCG can be of importance to better utilize it as a chemopreventive and chemotherapeutic agent.},
	doi = {10.1080/10408398.2016.1231168},
	pmid = {27645804 [Indexed for MEDLINE]}
}
